import { callMcpSkillsParallel } from "@/lib/ai/skills/mcp";
import { pickTopSemanticCandidates } from "@/lib/ai/skills/semantic-targeting";

export async function main() {
  const toolId = "294100e8-c648-4e5f-a254-95a14b56e398";

  const batch = await callMcpSkillsParallel({
    label: "sports-trending-markets-read",
    calls: [
      {
        key: "trending",
        toolId,
        toolName: "discover_trending_markets",
        args: {
          category: "sports",
          limit: 15,
        },
      },
    ],
  });

  const trendingResult =
    batch.results.find((entry) => entry.key === "trending") || null;
  const data =
    trendingResult && trendingResult.status === "fulfilled"
      ? trendingResult.value
      : null;

  const markets = Array.isArray(data?.trendingMarkets) ? data.trendingMarkets : [];

  const parseTrendSignal = (value) => {
    if (value == null) return null;
    const raw = String(value).trim().toLowerCase();
    const match = raw.match(/(\d+(?:\.\d+)?)/);
    if (!match) return null;
    const n = Number(match[1]);
    if (!Number.isFinite(n)) return null;
    if (raw.includes("x") || raw.includes("times")) return n;
    if (raw.includes("%")) return n / 100;
    return n;
  };

  const assessAlignment = (market) => {
    const why = String(market?.whyTrending || "").toLowerCase();
    const dir = String(market?.priceDirection || "").toLowerCase();

    const bullishWords = ["up", "rising", "surging", "spiking", "breakout", "bullish", "higher", "gaining"];
    const bearishWords = ["down", "falling", "dropping", "selloff", "bearish", "lower", "declining", "slipping"];

    const whyBullish = bullishWords.some((w) => why.includes(w));
    const whyBearish = bearishWords.some((w) => why.includes(w));
    const dirBullish = bullishWords.some((w) => dir.includes(w));
    const dirBearish = bearishWords.some((w) => dir.includes(w));

    if ((whyBullish && dirBullish) || (whyBearish && dirBearish)) return "aligned";
    if ((whyBullish && dirBearish) || (whyBearish && dirBullish)) return "misaligned";
    return "unclear";
  };

  const scoredCandidates = markets.map((m, index) => {
    const volumeVsAverage = parseTrendSignal(m?.volumeVsAverage);
    const alignment = assessAlignment(m);

    return {
      ...m,
      __index: index,
      __semanticScore: volumeVsAverage == null ? -Infinity : volumeVsAverage,
      __alignment: alignment,
    };
  });

  const ranked = pickTopSemanticCandidates({
    target: "find the sports trending market with the strongest volumeVsAverage signal and verify whether priceDirection aligns with the trend narrative in whyTrending",
    candidates: scoredCandidates,
    requiredTerms: ["volumeVsAverage", "priceDirection", "whyTrending"],
    avoidTerms: ["resolved", "inactive"],
    limit: 1,
  });

  const top = Array.isArray(ranked) && ranked.length > 0 ? ranked[0] : null;

  return {
    fetchedAt: data?.fetchedAt ?? null,
    totalActive: data?.totalActive ?? null,
    topCandidate: top
      ? {
          title: top.title ?? null,
          slug: top.slug ?? null,
          url: top.url ?? null,
          category: top.category ?? null,
          currentPrice: top.currentPrice ?? null,
          volume24h: top.volume24h ?? null,
          volumeVsAverage: top.volumeVsAverage ?? null,
          priceDirection: top.priceDirection ?? null,
          whyTrending: top.whyTrending ?? null,
          trendScore: top.__semanticScore,
          alignment: top.__alignment,
        }
      : null,
    analyzedCount: markets.length,
    batchTelemetry: batch.summary,
    note: top
      ? "Execution plan uses a single read batch, then deterministic semantic targeting and serial local analysis to choose the strongest sports trending market."
      : "No sports trending markets were returned by discover_trending_markets.",
  };
}

